#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-07-08

# test-quality-bar.sh - Asserts designated skills keep their "## Quality Bar" section.
#
# Quality Bar sections are falsifiable acceptance rubrics added to high-traffic
# skills (MengTo/Skills adoption). Once a skill carries one, a refactor
# must not silently drop it — graders, /ork:verify, and eval pipelines rely on it.
#
# Add a skill here after giving it a Quality Bar. The list only grows.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"

COVERED_SKILLS=(
    assess
    auto
    brainstorm
    commit
    cover
    create-pr
    design-context-extract
    design-stylecards
    design-to-code
    expect
    explore
    fix-issue
    implement
    review-pr
    verify
    visualize-plan
)

FAILED=0
CHECKED=0

echo "=========================================="
echo "Testing Quality Bar presence"
echo "=========================================="
echo

for skill in "${COVERED_SKILLS[@]}"; do
    CHECKED=$((CHECKED + 1))
    skill_file="$REPO_ROOT/src/skills/$skill/SKILL.md"

    if [[ ! -f "$skill_file" ]]; then
        echo "FAIL: $skill - SKILL.md not found (covered skill removed without updating this test?)"
        FAILED=$((FAILED + 1))
        continue
    fi

    if ! grep -q '^## Quality Bar' "$skill_file"; then
        echo "FAIL: $skill - '## Quality Bar' section missing"
        echo "      File: src/skills/$skill/SKILL.md"
        FAILED=$((FAILED + 1))
        continue
    fi

    # The section must contain at least 3 falsifiable bullet criteria.
    bullets=$(awk '/^## Quality Bar/{f=1; next} /^## /{f=0} f && /^- /' "$skill_file" | wc -l | tr -d ' ')
    if [[ "$bullets" -lt 3 ]]; then
        echo "FAIL: $skill - Quality Bar has only $bullets criteria (minimum 3)"
        FAILED=$((FAILED + 1))
        continue
    fi

    echo "PASS: $skill ($bullets criteria)"
done

echo
echo "=========================================="
echo "Checked: $CHECKED skills"
echo "Failed:  $FAILED"
echo "=========================================="

exit $((FAILED > 0 ? 1 : 0))
